#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long L,R; scanf("%lld %lld", &L, &R);
        long long ans = 2*(R - L) + 1;
        printf("%lld\n", ans);
    }
    return 0;
}

